// MongoDB example
public async Task<User> FindUser(string userId)
{
    var collection = database.GetCollection<User>("users");

    // Compliant - using proper filter builders
    var filter = Builders<User>.Filter.Eq(u => u.Id, userId);
    var result = await collection.Find(filter).FirstOrDefaultAsync();
    return result;
}

// Azure Cosmos DB example
public async Task<Document> GetDocument(string id)
{
    // Compliant - using parameterized queries
    var query = new SqlQuerySpec(
        "SELECT * FROM c WHERE c.id = @id",
        new SqlParameterCollection { new SqlParameter("@id", id) }
    );
    return await client.CreateDocumentQuery(collectionUri, query).FirstOrDefaultAsync();
}
